package policy

import (
	"context"
	"io"

	"github.com/sirupsen/logrus"

	"github.com/cilium/cilium/pkg/identity"
	"github.com/cilium/cilium/pkg/lock"
	"github.com/cilium/cilium/pkg/logging/logfields"
)

// PolicyAuditLogger provides structured logging of policy evaluation decisions
// for audit and debugging purposes.
type PolicyAuditLogger struct {
	mutex lock.Mutex
	log   *logrus.Logger
}

// NewPolicyAuditLogger creates a new PolicyAuditLogger with the specified log level.
// If output is nil, the logger will use the standard Cilium logging framework.
func NewPolicyAuditLogger(level logrus.Level, output io.Writer) *PolicyAuditLogger {
	logger := logrus.New()
	logger.SetLevel(level)

	if output != nil {
		logger.SetOutput(output)
		logger.SetFormatter(&logrus.JSONFormatter{})
	} else {
		// Use default Cilium logger when no output is specified
		logger = logrus.StandardLogger()
		logger.SetLevel(level)
	}

	return &PolicyAuditLogger{
		log: logger,
	}
}

// LogDecision logs a policy decision with the verdict and reason.
// This method is thread-safe.
func (pal *PolicyAuditLogger) LogDecision(identity identity.NumericIdentity, policy string, verdict string, reason string) {
	pal.mutex.Lock()
	defer pal.mutex.Unlock()

	scopedLog := pal.log.WithFields(logrus.Fields{
		logfields.Identity:    identity,
		"policy":              policy,
		"verdict":             verdict,
		"reason":              reason,
		logfields.LogSubsys:   "policy-audit",
	})

	scopedLog.Info("Policy decision logged")
}

// LogEvaluation logs the evaluation result of a policy against a SelectorCache.
// This method is thread-safe and captures the full evaluation context.
func (pal *PolicyAuditLogger) LogEvaluation(ctx context.Context, policyKey string, selectorCache *SelectorCache, result string) {
	pal.mutex.Lock()
	defer pal.mutex.Unlock()

	scopedLog := pal.log.WithFields(logrus.Fields{
		logfields.PolicyKey:   policyKey,
		"evaluation_result":   result,
		logfields.LogSubsys:   "policy-audit",
	})

	// Add context information if the SelectorCache is available
	if selectorCache != nil {
		scopedLog = scopedLog.WithField("selector_cache_size", len(selectorCache.idCache))
	}

	scopedLog.Debug("Policy evaluation logged")
}

// SetOutput sets the output writer for the audit logger.
// This method is thread-safe.
func (pal *PolicyAuditLogger) SetOutput(output io.Writer) {
	pal.mutex.Lock()
	defer pal.mutex.Unlock()

	if output != nil {
		pal.log.SetOutput(output)
		pal.log.SetFormatter(&logrus.JSONFormatter{})
	}
}

// SetLevel sets the log level for the audit logger.
// This method is thread-safe.
func (pal *PolicyAuditLogger) SetLevel(level logrus.Level) {
	pal.mutex.Lock()
	defer pal.mutex.Unlock()

	pal.log.SetLevel(level)
}

