package policy

import (
	"bytes"
	"context"
	"testing"

	"github.com/sirupsen/logrus"
	"github.com/stretchr/testify/require"

	"github.com/cilium/cilium/pkg/identity"
)

func TestPolicyAuditLoggerCreation(t *testing.T) {
	// Test creation with custom output
	buf := &bytes.Buffer{}
	logger := NewPolicyAuditLogger(logrus.InfoLevel, buf)
	require.NotNil(t, logger)

	// Test creation without custom output (uses default logger)
	logger2 := NewPolicyAuditLogger(logrus.DebugLevel, nil)
	require.NotNil(t, logger2)
}

func TestLogDecision(t *testing.T) {
	buf := &bytes.Buffer{}
	logger := NewPolicyAuditLogger(logrus.InfoLevel, buf)

	identity := identity.NumericIdentity(100)
	logger.LogDecision(identity, "test-policy", "allow", "matched selector")

	output := buf.String()
	require.Contains(t, output, "Policy decision logged")
}

func TestLogDecisionWithMultipleDecisions(t *testing.T) {
	buf := &bytes.Buffer{}
	logger := NewPolicyAuditLogger(logrus.InfoLevel, buf)

	// Log multiple decisions
	id1 := identity.NumericIdentity(100)
	id2 := identity.NumericIdentity(200)

	logger.LogDecision(id1, "policy1", "allow", "reason1")
	logger.LogDecision(id2, "policy2", "deny", "reason2")

	output := buf.String()
	require.Contains(t, output, "Policy decision logged")
}

func TestLogEvaluation(t *testing.T) {
	buf := &bytes.Buffer{}
	logger := NewPolicyAuditLogger(logrus.DebugLevel, buf)

	ctx := context.Background()
	logger.LogEvaluation(ctx, "test-key", nil, "evaluation_success")

	output := buf.String()
	require.Contains(t, output, "Policy evaluation logged")
}

func TestLogEvaluationWithSelectorCache(t *testing.T) {
	buf := &bytes.Buffer{}
	logger := NewPolicyAuditLogger(logrus.DebugLevel, buf)

	ctx := context.Background()
	cache := NewSelectorCache(identity.IdentityMap{
		100: identity.NewIdentity(100, []string{"test"}),
	})

	logger.LogEvaluation(ctx, "test-key", cache, "evaluation_success")

	output := buf.String()
	require.Contains(t, output, "Policy evaluation logged")
}

func TestSetOutput(t *testing.T) {
	buf1 := &bytes.Buffer{}
	logger := NewPolicyAuditLogger(logrus.InfoLevel, buf1)

	buf2 := &bytes.Buffer{}
	logger.SetOutput(buf2)

	logger.LogDecision(100, "policy", "allow", "reason")

	// Output should be in buf2, not buf1
	require.Equal(t, "", buf1.String())
	require.NotEqual(t, "", buf2.String())
}

func TestSetLevel(t *testing.T) {
	buf := &bytes.Buffer{}
	logger := NewPolicyAuditLogger(logrus.InfoLevel, buf)

	// Set level to error (should not log debug messages)
	logger.SetLevel(logrus.ErrorLevel)

	// Try to log at debug level (should not appear)
	ctx := context.Background()
	logger.LogEvaluation(ctx, "test-key", nil, "evaluation_success")

	require.Equal(t, "", buf.String())
}

func TestThreadSafety(t *testing.T) {
	buf := &bytes.Buffer{}
	logger := NewPolicyAuditLogger(logrus.InfoLevel, buf)

	// Run multiple goroutines accessing the logger concurrently
	done := make(chan bool, 10)

	for i := 0; i < 10; i++ {
		go func(idx int) {
			id := identity.NumericIdentity(100 + idx)
			logger.LogDecision(id, "policy", "allow", "reason")
			ctx := context.Background()
			logger.LogEvaluation(ctx, "key", nil, "result")
			done <- true
		}(i)
	}

	// Wait for all goroutines to complete
	for i := 0; i < 10; i++ {
		<-done
	}

	output := buf.String()
	require.NotEqual(t, "", output)
}

func TestJSONFormattedOutput(t *testing.T) {
	buf := &bytes.Buffer{}
	logger := NewPolicyAuditLogger(logrus.InfoLevel, buf)

	identity := identity.NumericIdentity(100)
	logger.LogDecision(identity, "test-policy", "allow", "matched")

	output := buf.String()
	// Check that output contains JSON fields (indicated by quotes and colons)
	require.Contains(t, output, ":")
}

